#include <stdio.h>
#include <string.h>

// Inner structure for address
struct Address {
    char city[30];
    char state[30];
    int pincode;
};

// Inner structure for salary
struct Salary {
    float basic;
    float hra;
    float da;
};

// Outer nested structure for employee
struct Employee {
    char name[50];
    int age;
    struct Address addr;  // Nested structure
    struct Salary sal;    // Nested structure
};

void displayEmployee(struct Employee e) {
    printf("Name: %s\n", e.name);
    printf("Age: %d\n", e.age);
    printf("City: %s\n", e.addr.city);
    printf("State: %s\n", e.addr.state);
    printf("Pincode: %d\n", e.addr.pincode);
    printf("Basic Salary: %.2f\n", e.sal.basic);
    printf("HRA: %.2f\n", e.sal.hra);
    printf("DA: %.2f\n", e.sal.da);
    printf("Total: %.2f\n", e.sal.basic + e.sal.hra + e.sal.da);
}

int main() {
    // Initializing nested structure
    struct Employee emp = {
        "John Doe",
        30,
        {"Delhi", "Delhi", 110001},
        {50000, 10000, 5000}
    };

    displayEmployee(emp);

    // Accessing via pointer
    struct Employee *ptr = &emp;
    printf("\nVia Pointer - City: %s\n", ptr->addr.city);

    return 0;
}

#include <stdio.h>

// Define nested structure for Date
struct Date {
    int day;
    int month;
    int year;
};

// Function to display date - PASS BY VALUE
void displayDateByValue(struct Date d) {
    printf("Date: %d/%d/%d\n", d.day, d.month, d.year);
    printf("Address of parameter: %p\n", (void*)&d);
}

// Function to modify date - PASS BY REFERENCE
void modifyDateByReference(struct Date *d, int newDay) {
    d->day = newDay;  // Arrow operator for nested pointer
    printf("Modified via pointer\n");
}

// Function returning nested structure
struct Date getTomorrow(struct Date today) {
    struct Date tomorrow;
    tomorrow.day = today.day + 1;
    tomorrow.month = today.month;
    tomorrow.year = today.year;
    return tomorrow;
}

int main() {
    struct Date today = {15, 8, 2024};

    printf("Original date: %d/%d/%d\n", today.day, today.month, today.year);
    printf("Address of original: %p\n", (void*)&today);

    // Pass by value - creates copy
    displayDateByValue(today);

    // Pass by reference - uses original
    modifyDateByReference(&today, 16);
    printf("After modification: %d/%d/%d\n", today.day, today.month, today.year);

    // Return nested structure
    struct Date tomorrow = getTomorrow(today);
    printf("Tomorrow: %d/%d/%d\n", tomorrow.day, tomorrow.month, tomorrow.year);

    return 0;
}

// Java equivalent of nested structures using composition

// Inner class (equivalent to inner structure)
class Address {
    private String city;
    private String state;
    private int pincode;

    public Address(String city, String state, int pincode) {
        this.city = city;
        this.state = state;
        this.pincode = pincode;
    }

    public String getCity() { return city; }
    public void setCity(String city) { this.city = city; }
}

// Outer class using inner class (composition)
class Employee {
    private String name;
    private int id;
    private Address address;  // Nested object

    public Employee(String name, int id, Address address) {
        this.name = name;
        this.id = id;
        this.address = address;
    }

    public void display() {
        System.out.println("Name: " + name);
        System.out.println("ID: " + id);
        System.out.println("City: " + address.getCity());
    }
}

public class Main {
    public static void main(String[] args) {
        // Creating nested objects (like nested structure initialization)
        Address addr = new Address("Delhi", "Delhi", 110001);
        Employee emp = new Employee("John", 101, addr);

        // Accessing nested members
        emp.display();

        // Direct access through getter (like emp.address.city)
        System.out.println("City via getter: " + emp.getClass());
    }
}
